// ============================================================
// v10.0 – KONTAKTE: vCard → Markdown
// Fix: Nur geänderte Kontakte schreiben → kein SMB-Timeout
//      aktualisiert-Feld wird beim Vergleich ignoriert
// cleanName() → Anzeigename im Markdown
// sanitize()   → Dateiname (keine Leerzeichen, keine Sonderzeichen)
// ============================================================
const fs = require('fs');
const outputBase = $('Konfiguration').first().json.OUTPUT_BASE;
const outputDir = outputBase + '/Kontakte/';

fs.mkdirSync(outputDir, { recursive: true });

const rawText = $input.first().json.data || '';

if (!rawText.includes('BEGIN:VCARD')) {
  return [{ json: { error: 'Keine vCard-Daten erhalten', preview: rawText.substring(0, 200) } }];
}

const vcardBlocks = rawText
  .split(/(?=BEGIN:VCARD)/)
  .map(b => b.trim())
  .filter(b => b.startsWith('BEGIN:VCARD'));

const results = [];

for (const block of vcardBlocks) {
  try {
    const contact = parseVCard(block);
    if (!contact.rawName) continue;

    const displayName = cleanName(contact.rawName);
    const filename = sanitize(contact.rawName) + '.md';
    const fullPath = outputDir + filename;

    const md = vCardToMarkdown(contact, displayName);

    // Nur schreiben wenn Inhalt geändert (aktualisiert-Feld ignorieren)
    let existing = '';
    try { existing = fs.readFileSync(fullPath, 'utf-8'); } catch(e) {}

    if (stripDate(md) !== stripDate(existing)) {
      fs.writeFileSync(fullPath, md, 'utf-8');
      results.push({ json: { status: 'written', filename, displayName } });
    } else {
      results.push({ json: { status: 'unchanged', filename, displayName } });
    }
  } catch (e) {
    results.push({ json: { status: 'error', error: e.message } });
  }
}

return results;

// ---- Hilfsfunktionen ----

// Entfernt aktualisiert-Zeile für Vergleich (ändert sich täglich)
function stripDate(s) {
  return s.replace(/^aktualisiert: .+$/m, '');
}

function parseVCard(text) {
  const unfolded = text.replace(/\r?\n[ \t]/g, '');
  const lines = unfolded.split(/\r?\n/);
  const c = { emails: [], phones: [], urls: [] };

  for (const line of lines) {
    const colonIdx = line.indexOf(':');
    if (colonIdx === -1) continue;
    const key = line.substring(0, colonIdx).toUpperCase();
    const value = line.substring(colonIdx + 1).trim();
    if (!value) continue;

    if (key === 'FN') {
      c.rawName = value;
    } else if (key === 'N' && !c.rawName) {
      const parts = value.split(';');
      const assembled = [parts[1], parts[0]].filter(p => p.trim()).join(' ');
      if (assembled.trim()) c.rawName = assembled;
    } else if (key.startsWith('EMAIL')) {
      c.emails.push(value);
    } else if (key.startsWith('TEL')) {
      c.phones.push(value);
    } else if (key === 'ORG') {
      c.org = value.replace(/;+$/, '').replace(/;/g, ', ');
    } else if (key === 'TITLE') {
      c.title = value;
    } else if (key === 'NOTE') {
      c.note = value.replace(/\\n/g, '\n').replace(/\\,/g, ',');
    } else if (key === 'BDAY') {
      c.birthday = formatDate(value);
    } else if (key.startsWith('URL') || key === 'URL') {
      c.urls.push(value);
    } else if (key.startsWith('ADR')) {
      const parts = value.split(';');
      const addr = parts.slice(2).filter(p => p.trim()).join(', ');
      if (addr) c.address = addr;
    } else if (key === 'NICKNAME') {
      c.nickname = value;
    } else if (key === 'CATEGORIES') {
      c.categories = value;
    }
  }
  return c;
}

function cleanName(raw) {
  return raw
    .replace(/,\s*/g, ' ')
    .replace(/-\s+/g, '-')
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitize(raw) {
  return cleanName(raw)
    .replace(/\s+/g, '-')
    .replace(/[\/\\?%*:|"<>]/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .trim();
}

function vCardToMarkdown(c, displayName) {
  const today = new Date().toISOString().split('T')[0];
  const lines = [
    '---',
    'type: contact',
    `name: "${displayName}"`,
    `aktualisiert: ${today}`,
    'tags:',
    '  - kontakt',
  ];
  if (c.org) lines.push(`organisation: "${c.org}"`);
  if (c.emails[0]) lines.push(`email: "${c.emails[0]}"`);
  if (c.phones[0]) lines.push(`telefon: "${c.phones[0]}"`);
  if (c.birthday) lines.push(`geburtstag: "${c.birthday}"`);
  lines.push('---', '', `# ${displayName}`, '');

  if (c.title) lines.push(`**Position:** ${c.title}  `);
  if (c.org) lines.push(`**Organisation:** ${c.org}  `);
  if (c.emails.length) c.emails.forEach(e => lines.push(`**E-Mail:** ${e}  `));
  if (c.phones.length) c.phones.forEach(p => lines.push(`**Telefon:** ${p}  `));
  if (c.address) lines.push(`**Adresse:** ${c.address}  `);
  if (c.birthday) lines.push(`**Geburtstag:** ${c.birthday}  `);
  if (c.urls.length) c.urls.forEach(u => lines.push(`**Website:** ${u}  `));
  if (c.note) lines.push('', '## Notizen', '', c.note);

  return lines.join('\n');
}

function formatDate(d) {
  if (!d) return d;
  if (d.includes('-')) return d.substring(0, 10);
  if (d.length >= 8) return `${d.substring(0, 4)}-${d.substring(4, 6)}-${d.substring(6, 8)}`;
  return d;
}

// ============================================================
// v10.0 – TERMINE: ICS → Markdown
// Fix: Nur geänderte Termine schreiben → kein SMB-Timeout
//      aktualisiert-Feld wird beim Vergleich ignoriert
// Format: YYYY-MM-DD-Terminname.md
// ============================================================
const fs = require('fs');
const outputBase = $('Konfiguration').first().json.OUTPUT_BASE;
const outputDir = outputBase + '/Termine/';

fs.mkdirSync(outputDir, { recursive: true });

const rawText = $input.first().json.data || '';

if (!rawText.includes('BEGIN:VCALENDAR')) {
  return [{ json: { error: 'Keine ICS-Daten erhalten', preview: rawText.substring(0, 200) } }];
}

const unfolded = rawText.replace(/\r?\n[ \t]/g, '');

const eventBlocks = [];
const eventRegex = /BEGIN:VEVENT[\s\S]*?END:VEVENT/g;
let match;
while ((match = eventRegex.exec(unfolded)) !== null) {
  eventBlocks.push(match[0]);
}

const results = [];

for (const block of eventBlocks) {
  try {
    const event = parseEvent(block);
    if (!event.summary) continue;

    const displayTitle = event.summary;
    const datePrefix = event.startDate || 'undatiert';
    const filename = sanitize(`${datePrefix}-${displayTitle}`) + '.md';
    const fullPath = outputDir + filename;

    const md = eventToMarkdown(event, displayTitle);

    // Nur schreiben wenn Inhalt geändert (aktualisiert-Feld ignorieren)
    let existing = '';
    try { existing = fs.readFileSync(fullPath, 'utf-8'); } catch(e) {}

    if (stripDate(md) !== stripDate(existing)) {
      fs.writeFileSync(fullPath, md, 'utf-8');
      results.push({ json: { status: 'written', filename, displayTitle } });
    } else {
      results.push({ json: { status: 'unchanged', filename, displayTitle } });
    }
  } catch (e) {
    results.push({ json: { status: 'error', error: e.message } });
  }
}

return results;

// ---- Hilfsfunktionen ----

function stripDate(s) {
  return s.replace(/^aktualisiert: .+$/m, '');
}

function parseEvent(text) {
  const lines = text.split(/\r?\n/);
  const e = {};

  for (const line of lines) {
    const colonIdx = line.indexOf(':');
    if (colonIdx === -1) continue;
    const key = line.substring(0, colonIdx).split(';')[0].toUpperCase();
    const value = line.substring(colonIdx + 1).trim();

    switch (key) {
      case 'SUMMARY':     e.summary = value.replace(/\\,/g, ',').replace(/\\n/g, '\n'); break;
      case 'DTSTART':     Object.assign(e, parseDateTime(value, 'start')); break;
      case 'DTEND':       Object.assign(e, parseDateTime(value, 'end')); break;
      case 'DURATION':    e.duration = value; break;
      case 'LOCATION':    e.location = value.replace(/\\,/g, ',').replace(/\\n/g, ', ').replace(/\;/g, ';'); break;
      case 'DESCRIPTION': e.description = value.replace(/\\n/g, '\n').replace(/\\,/g, ',').trim(); break;
      case 'STATUS':      e.status = value; break;
      case 'CATEGORIES':  e.categories = value.split(',').map(c => c.trim()); break;
      case 'URL':         e.url = value; break;
      case 'RRULE':       e.rrule = value; break;
      case 'UID':         e.uid = value; break;
      case 'ORGANIZER':   e.organizer = value.replace('mailto:', ''); break;
    }
  }
  return e;
}

function parseDateTime(value, prefix) {
  const result = {};
  if (value.length === 8) {
    result[prefix + 'Date'] = `${value.substring(0, 4)}-${value.substring(4, 6)}-${value.substring(6, 8)}`;
    result[prefix + 'Time'] = null;
    result[prefix + 'AllDay'] = true;
    return result;
  }
  const d = value.substring(0, 8);
  const t = value.substring(9, 15);
  result[prefix + 'Date'] = `${d.substring(0, 4)}-${d.substring(4, 6)}-${d.substring(6, 8)}`;
  result[prefix + 'Time'] = `${t.substring(0, 2)}:${t.substring(2, 4)}`;
  result[prefix + 'AllDay'] = false;
  return result;
}

function sanitize(raw) {
  return raw
    .replace(/,\s*/g, '-')
    .replace(/\s+/g, '-')
    .replace(/[\/\\?%*:|"<>]/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .trim()
    .substring(0, 120);
}

function eventToMarkdown(e, displayTitle) {
  const today = new Date().toISOString().split('T')[0];
  const lines = [
    '---',
    'type: termin',
    `title: "${displayTitle}"`,
    `datum: ${e.startDate || ''}`,
    `aktualisiert: ${today}`,
    'tags:',
    '  - termin',
  ];
  if (e.startTime) lines.push(`uhrzeit_start: "${e.startTime}"`);
  if (e.endTime) lines.push(`uhrzeit_ende: "${e.endTime}"`);
  if (e.location) lines.push(`ort: "${e.location.substring(0, 200)}"`);
  if (e.status) lines.push(`status: ${e.status.toLowerCase()}`);
  if (e.categories?.length) lines.push(`kategorien: [${e.categories.join(', ')}]`);
  if (e.startAllDay) lines.push('ganztaegig: true');
  lines.push('---', '', `# ${displayTitle}`, '');

  lines.push(`**Datum:** ${e.startDate}  `);
  if (e.startTime) {
    const timeStr = e.endTime ? `${e.startTime} – ${e.endTime} Uhr` : `${e.startTime} Uhr`;
    lines.push(`**Uhrzeit:** ${timeStr}  `);
  }
  if (e.location) lines.push(`**Ort:** ${e.location}  `);
  if (e.organizer) lines.push(`**Organisator:** ${e.organizer}  `);
  if (e.url) lines.push(`**Link:** ${e.url}  `);
  if (e.rrule) lines.push(`**Wiederholung:** ${parseRRule(e.rrule)}  `);
  if (e.description) lines.push('', '## Beschreibung', '', e.description);

  return lines.join('\n');
}

function parseRRule(rrule) {
  const map = { DAILY: 'täglich', WEEKLY: 'wöchentlich', MONTHLY: 'monatlich', YEARLY: 'jährlich' };
  const freq = rrule.match(/FREQ=(\w+)/)?.[1];
  return freq ? (map[freq] || freq) : rrule;
}
